class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        def is_palindrome(num: int) -> bool:
            return str(num) == str(num)[::-1]

        max_num = int('9' * n)
        for num in range(max_num, 10**(n-1) - 1, -1):
            if num % k == 0 and is_palindrome(num):
                return str(num)
